9	export async function getPending(page = 1, limit = 20) {
10	  const skip = (page - 1) * limit;
11	  const [items, total] = await Promise.all([
12	    ContentReview.find({ status: ContentReviewStatus.PENDING }).sort({ createdAt: -1 }).skip(skip).limit(limit),
13	    ContentReview.countDocuments({ status: ContentReviewStatus.PENDING }),
14	  ]);
15	  return { items, total, page, limit };
