18	export async function reviewContent(id: string, reviewedBy: string, status: ContentReviewStatus, reviewNotes?: string) {
19	  const review = await ContentReview.findById(id);
20	  if (!review) throw new NotFoundError('Content review not found');
21	  review.status = status;
22	  review.reviewedBy = reviewedBy as any;
23	  review.reviewNotes = reviewNotes;
24	  review.reviewedAt = new Date();
25	  await review.save();
26	
27	  // Propagate decision to the source content
28	  await propagateDecision(review.contentType as ReviewableContentType, review.contentId.toString(), status);
29	
30	  return review;
31	}
32	
33	async function propagateDecision(contentType: ReviewableContentType, contentId: string, status: ContentReviewStatus) {
34	  if (contentType === ReviewableContentType.JOB_MESSAGE) {
35	    const { JobMessage } = await import('../models');
36	    await JobMessage.findByIdAndUpdate(contentId, { reviewStatus: status });
37	  } else if (contentType === ReviewableContentType.PORTFOLIO) {
38	    const { Portfolio } = await import('../models');
39	    await Portfolio.findByIdAndUpdate(contentId, { reviewStatus: status });
40	  }
41	}
