5	export const adminReviewSchema = z.object({
6	  status: z.enum(['verified', 'needs_changes', 'rejected']).optional(),
7	  decision: z.enum(['approved', 'verified', 'needs_changes', 'rejected']).optional(),
8	  reviewNotes: z.string().max(1000).optional(),
9	  rejectionReason: z.string().max(1000).optional(),
10	}).refine(data => data.status || data.decision, {
11	  message: 'Either status or decision is required',
