18	export async function submit(req: Request, res: Response, next: NextFunction): Promise<void> {
19	  try {
20	    if (!req.files || (Array.isArray(req.files) && req.files.length === 0)) {
21	      res.status(400).json({ code: 400, msg: 'No documents uploaded' });
22	      return;
23	    }
24	    // Handle both multer.fields() and multer.array() upload patterns
25	    let allFiles: Express.Multer.File[] = [];
26	    if (Array.isArray(req.files)) {
27	      allFiles = req.files;
28	    } else if (req.files && typeof req.files === 'object') {
29	      const fileMap = req.files as { [fieldname: string]: Express.Multer.File[] };
30	      for (const field of Object.values(fileMap)) {
31	        allFiles.push(...field);
32	      }
33	    }
34	    // Validate file type/format/size then store
35	    const { validateAndStore } = await import('../services/file.service');
36	    const storedPaths: string[] = [];
37	    const checksums: string[] = [];
38	    for (const file of allFiles) {
39	      const attachment = await validateAndStore({
40	        buffer: file.buffer,
41	        originalName: file.originalname,
42	        mimeType: file.mimetype,
43	        parentType: 'verification',
44	        parentId: req.user!.userId,
45	        uploadedBy: req.user!.userId,
46	      });
47	      storedPaths.push(attachment.storagePath);
48	      checksums.push(attachment.checksum);
49	    }
50	    const result = await verificationService.submitVerification({
51	      photographerId: req.user!.userId,
52	      realName: req.body.realName || req.body.documentType || 'Not provided',
53	      qualificationType: req.body.qualificationType || req.body.documentType || 'general',
54	      issuingAuthority: req.body.issuingAuthority,
55	      idDocumentPath: storedPaths[0] || '',
56	      qualificationDocPaths: storedPaths.slice(1),
57	      fileChecksums: checksums,
58	    });
59	    res.status(201).json(result);
60	  } catch (err) {
61	    next(err);
62	  }
63	}
