62	export interface AdminReviewInput {
63	  verificationId: string;
64	  reviewerId: string;
65	  decision: VerificationStatus.VERIFIED | VerificationStatus.REJECTED | VerificationStatus.NEEDS_CHANGES;
66	  reason: string;
67	}
68	
69	export async function adminReview(input: AdminReviewInput) {
70	  if (!input.reason || input.reason.trim().length === 0) {
71	    throw new ValidationError('A review reason is mandatory');
72	  }
73	
74	  const verification = await Verification.findById(input.verificationId);
75	  if (!verification) {
76	    throw new NotFoundError('Verification not found');
77	  }
78	
79	  if (
80	    verification.status !== VerificationStatus.SUBMITTED &&
81	    verification.status !== VerificationStatus.NEEDS_CHANGES
82	  ) {
83	    throw new ValidationError(
84	      `Cannot review a verification with status: ${verification.status}`
85	    );
86	  }
87	
88	  // Run compliance hook before approving
89	  if (input.decision === VerificationStatus.VERIFIED) {
90	    const complianceResult = await beforeVerificationApprove(verification.toObject());
91	    if (!complianceResult.allow) {
92	      throw new ForbiddenError(
93	        complianceResult.reason || 'Compliance check failed for verification approval'
94	      );
95	    }
96	  }
97	
98	  verification.status = input.decision;
99	  verification.reviewReason = input.reason;
100	  verification.reviewedBy = input.reviewerId as any;
101	  verification.reviewedAt = new Date();
102	  await verification.save();
103	
104	  const auditAction =
105	    input.decision === VerificationStatus.VERIFIED
106	      ? AUDIT_EVENTS.KYC_APPROVE
107	      : input.decision === VerificationStatus.REJECTED
108	        ? AUDIT_EVENTS.KYC_REJECT
109	        : AUDIT_EVENTS.KYC_REVIEW;
110	
111	  await logEvent({
112	    actorId: input.reviewerId,
113	    action: auditAction,
114	    resource: 'verification',
115	    resourceId: verification._id.toString(),
116	    details: { decision: input.decision, reason: input.reason },
117	    outcome: 'success',
118	  });
119	
120	  return verification;
121	}
