137	/**
138	 * Get verification record. Non-admin viewers get masked identifiers.
139	 */
140	export async function getVerification(
141	  verificationId: string,
142	  viewerRole: Role
143	) {
144	  const verification = await Verification.findById(verificationId);
145	  if (!verification) {
146	    throw new NotFoundError('Verification not found');
147	  }
148	
149	  const obj = verification.toObject() as any;
150	
151	  if (viewerRole === Role.ADMIN) {
152	    // Decrypt for admin
153	    try {
154	      obj.realName = decrypt(obj.realName, 'government_id');
155	      obj.idDocumentPath = decrypt(obj.idDocumentPath, 'government_id');
156	      obj.qualificationDocPaths = obj.qualificationDocPaths.map(
157	        (p: string) => decrypt(p, 'qualification_documents')
158	      );
159	    } catch {
160	      // If decryption fails, return as-is
161	    }
162	  } else {
163	    // Mask identifiers for non-admin
164	    try {
165	      const decryptedName = decrypt(obj.realName, 'government_id');
166	      obj.realName = maskIdentifier(decryptedName);
167	    } catch {
168	      obj.realName = '***';
169	    }
170	    obj.idDocumentPath = '[REDACTED]';
171	    obj.qualificationDocPaths = obj.qualificationDocPaths.map(() => '[REDACTED]');
172	  }
173	
174	  return obj;
175	}
