10	  const { checkConsent } = await import('./dataCategoryConsent.service');
11	  const { hasConsent } = await checkConsent(reporterId, 'account_identity');
12	  if (!hasConsent) {
13	    throw new ForbiddenError('Consent for account_identity data category is required before submitting reports');
14	  }
15	
16	  const today = new Date();
17	  today.setHours(0, 0, 0, 0);
18	  const count = await Report.countDocuments({
19	    reporterId,
