51	export async function reviewReport(id: string, adminId: string, status: ReportStatus, notes?: string, resolution?: string) {
52	  const report = await Report.findById(id);
53	  if (!report) throw new NotFoundError('Report not found');
54	
55	  const validTransitions: Record<string, string[]> = {
56	    [ReportStatus.SUBMITTED]: [ReportStatus.UNDER_REVIEW],
57	    [ReportStatus.UNDER_REVIEW]: [ReportStatus.NEEDS_MORE_INFO, ReportStatus.ACTION_TAKEN, ReportStatus.REJECTED],
58	    [ReportStatus.NEEDS_MORE_INFO]: [ReportStatus.UNDER_REVIEW, ReportStatus.CLOSED],
59	    [ReportStatus.ACTION_TAKEN]: [ReportStatus.CLOSED],
60	    [ReportStatus.REJECTED]: [ReportStatus.CLOSED],
61	  };
62	  if (!validTransitions[report.status]?.includes(status)) {
63	    throw new ValidationError(`Cannot transition from ${report.status} to ${status}`);
64	  }
65	
66	  report.status = status;
67	  report.statusHistory.push({ status, changedBy: adminId as any, changedAt: new Date(), notes });
68	  if (resolution) report.resolution = resolution;
69	  report.reviewedBy = adminId as any;
70	  report.reviewedAt = new Date();
71	  return report.save();
72	}
