1	import crypto from 'crypto';
2	import { Request, Response, NextFunction } from 'express';
3	import { Nonce } from '../models/Nonce';
4	import { config } from '../config';
5	import { ConflictError, ValidationError } from '../utils/errors';
6	
7	const NONCE_EXEMPT_PATHS = [
8	  'GET:/api/health',
9	];
10	
11	export async function nonceReplay(req: Request, _res: Response, next: NextFunction): Promise<void> {
12	  try {
13	    const routeKey = `${req.method}:${req.path}`;
14	    if (NONCE_EXEMPT_PATHS.includes(routeKey)) {
15	      return next();
16	    }
17	
18	    const nonce = req.headers['x-nonce'] as string;
19	    const timestamp = req.headers['x-timestamp'] as string;
20	
21	    if (!nonce || !timestamp) {
22	      return next(new ValidationError('X-Nonce and X-Timestamp headers are required'));
23	    }
24	
25	    const requestTime = parseInt(timestamp, 10);
26	    if (isNaN(requestTime)) {
27	      return next(new ValidationError('Invalid X-Timestamp header'));
28	    }
29	
30	    const now = Date.now();
31	    const diff = Math.abs(now - requestTime);
32	
33	    if (diff > config.nonceWindowMs + config.clockSkewMs) {
34	      return next(new ValidationError('Request timestamp outside acceptable window'));
35	    }
36	
37	    // Bind the nonce to the request method and path so a captured nonce
38	    // cannot be replayed against a different endpoint.
39	    const boundNonce = crypto
40	      .createHash('sha256')
41	      .update(`${nonce}:${req.method}:${req.path}`)
42	      .digest('hex');
43	
44	    const existing = await Nonce.findOne({ nonce: boundNonce });
45	    if (existing) {
46	      return next(new ConflictError('Duplicate nonce detected - possible replay attack'));
47	    }
48	
49	    await Nonce.create({ nonce: boundNonce, timestamp: new Date(requestTime) });
50	    req.nonce = nonce;
51	    next();
52	  } catch (err) {
53	    next(err);
54	  }
55	}
