193	export async function getSettlement(settlementId: string, requesterId: string) {
194	  const settlement = await Settlement.findById(settlementId);
195	  if (!settlement) {
196	    throw new NotFoundError('Settlement not found');
197	  }
198	
199	  // Look up the requester's role from DB — never trust caller-supplied role
200	  const { User } = await import('../models');
201	  const requester = await User.findById(requesterId);
202	  const requesterRole = requester?.role;
203	
204	  // Object-level authorization: only participants or admins
205	  if (requesterRole !== 'admin') {
206	    const isParticipant =
207	      settlement.clientId.toString() === requesterId ||
208	      settlement.photographerId.toString() === requesterId;
209	    if (!isParticipant) {
210	      throw new ForbiddenError('You do not have access to this settlement');
211	    }
212	  }
213	
214	  const lineItems = await SettlementLineItem.find({ settlementId }).sort({ createdAt: 1 }).lean();
215	
216	  return { settlement, lineItems };
217	}
218	
219	export async function getSettlementsByJob(jobId: string) {
220	  return Settlement.find({ jobId }).sort({ createdAt: -1 }).lean();
221	}
