20	  const [adjSaving, setAdjSaving] = useState(false);
21	
22	  const fetchData = async () => {
23	    if (!id) return;
24	    try {
25	      const [sRes, pRes] = await Promise.all([
26	        settlementsApi.getById(id),
27	        settlementsApi.getPayments(id).catch(() => ({ data: [] })),
28	      ]);
29	      const sData = sRes.data.settlement || sRes.data;
30	      setSettlement(sData);
31	      setLineItems(sRes.data.lineItems || []);
32	      setPayments(pRes.data.items || pRes.data || []);
33	    } catch (err: any) {
34	      setError(err.response?.data?.msg || 'Failed to load settlement');
35	    } finally {
36	      setLoading(false);
37	    }
38	  };
39	
40	  useEffect(() => { fetchData(); }, [id]);
41	
42	  const handleApprove = async () => {
43	    if (!id) return;
44	    try {
45	      await settlementsApi.approve(id);
46	      await fetchData();
47	    } catch (err: any) {
48	      setError(err.response?.data?.msg || 'Failed to approve');
49	    }
50	  };
51	
52	  const handleAddAdjustment = async (e: React.FormEvent) => {
53	    e.preventDefault();
54	    if (!id) return;
55	    setAdjSaving(true);
56	    try {
57	      await settlementsApi.addAdjustment(id, {
58	        amountCents: Math.round(parseFloat(adjForm.amountCents) * 100),
59	        reason: adjForm.reason,
60	      });
61	      setShowAdjForm(false);
62	      setAdjForm({ amountCents: '', reason: '' });
63	      await fetchData();
64	    } catch (err: any) {
65	      setError(err.response?.data?.msg || 'Failed to add adjustment');
