86	
87	  if (loading) return <LoadingSpinner message="Loading settlement..." />;
88	  if (!settlement) return <div className="text-gray-500">Settlement not found.</div>;
89	
90	  return (
91	    <div className="max-w-3xl mx-auto">
92	      <div className="flex items-center justify-between mb-6">
93	        <div>
94	          <h1 className="text-2xl font-bold">Settlement Details</h1>
