98	        </div>
99	        <div className="flex gap-2">
100	          <button onClick={() => handleExport('pdf')} className="border px-3 py-1.5 rounded text-sm hover:bg-gray-50">Export PDF</button>
101	          <button onClick={() => handleExport('csv')} className="border px-3 py-1.5 rounded text-sm hover:bg-gray-50">Export CSV</button>
102	        </div>
103	      </div>
104	      {error && <div className="bg-red-50 text-red-600 p-3 rounded mb-4 text-sm">{error}</div>}
105	
106	      <div className="bg-white rounded-lg shadow mb-6">
107	        <div className="px-6 py-4 border-b flex items-center justify-between">
108	          <h2 className="font-semibold">Summary</h2>
109	          <StatusBadge status={settlement.status} size="md" />
