111	        <dl className="divide-y">
112	          <div className="px-6 py-3 flex justify-between">
113	            <dt className="text-sm text-gray-500">Subtotal</dt>
114	            <dd><MoneyDisplay cents={settlement.subtotalCents || 0} /></dd>
115	          </div>
116	          <div className="px-6 py-3 flex justify-between">
117	            <dt className="text-sm text-gray-500">Adjustments</dt>
118	            <dd><MoneyDisplay cents={settlement.adjustmentCents || 0} showSign /></dd>
119	          </div>
120	          <div className="px-6 py-3 flex justify-between font-semibold">
121	            <dt className="text-sm">Final Amount</dt>
122	            <dd><MoneyDisplay cents={settlement.finalAmountCents || 0} /></dd>
