130	          <div className="px-6 py-3 flex justify-between text-sm">
131	            <span>Photographer Approved: <strong className={settlement.photographerApproved ? 'text-green-600' : 'text-gray-400'}>{settlement.photographerApproved ? 'Yes' : 'No'}</strong></span>
132	            <span>Client Approved: <strong className={settlement.clientApproved ? 'text-green-600' : 'text-gray-400'}>{settlement.clientApproved ? 'Yes' : 'No'}</strong></span>
133	          </div>
134	        </dl>
135	        <div className="px-6 py-4 border-t flex gap-2">
136	          <button onClick={handleApprove} className="bg-green-600 text-white px-4 py-2 rounded text-sm hover:bg-green-700">
137	            Approve Settlement
138	          </button>
139	          <button onClick={() => setShowAdjForm(!showAdjForm)} className="border px-4 py-2 rounded text-sm hover:bg-gray-50">
140	            {showAdjForm ? 'Cancel' : 'Add Adjustment'}
141	          </button>
142	          <Link to={`/settlements/${id}/pay`} className="border px-4 py-2 rounded text-sm hover:bg-gray-50">
143	            Record Payment
144	          </Link>
145	        </div>
146	      </div>
147	
148	      {showAdjForm && (
149	        <form onSubmit={handleAddAdjustment} className="bg-white rounded-lg shadow p-6 mb-6 space-y-4">
150	          <h3 className="font-semibold text-sm">Add Adjustment</h3>
151	          <div className="grid grid-cols-2 gap-4">
152	            <div>
153	              <label className="block text-sm font-medium text-gray-700 mb-1">Amount ($)</label>
154	              <input type="number" step="0.01" value={adjForm.amountCents} onChange={e => setAdjForm({ ...adjForm, amountCents: e.target.value })} required className="w-full border rounded px-3 py-2 text-sm" placeholder="Use negative for deductions" />
155	            </div>
156	            <div>
157	              <label className="block text-sm font-medium text-gray-700 mb-1">Reason</label>
158	              <input type="text" value={adjForm.reason} onChange={e => setAdjForm({ ...adjForm, reason: e.target.value })} required className="w-full border rounded px-3 py-2 text-sm" />
159	            </div>
160	          </div>
161	          <button type="submit" disabled={adjSaving} className="bg-primary-600 text-white px-4 py-2 rounded text-sm hover:bg-primary-700 disabled:opacity-50">
162	            {adjSaving ? 'Adding...' : 'Add Adjustment'}
163	          </button>
164	        </form>
165	      )}
166	
167	      <div className="bg-white rounded-lg shadow">
168	        <div className="px-6 py-4 border-b">
169	          <h2 className="font-semibold">Payments</h2>
170	        </div>
171	        {payments.length === 0 ? (
172	          <p className="p-6 text-sm text-gray-500">No payments recorded yet.</p>
