4	  mongoUri: process.env.MONGODB_URI || 'mongodb://localhost:27017/lenswork',
5	  jwtSecret: process.env.JWT_SECRET || '',
6	  masterEncryptionKey: process.env.MASTER_ENCRYPTION_KEY || '',
7	  bcryptRounds: parseInt(process.env.BCRYPT_ROUNDS || '12', 10),
