18	export function validateConfig(): void {
19	  if (!config.jwtSecret || config.jwtSecret.length < 32) {
20	    throw new Error('JWT_SECRET must be at least 32 characters');
21	  }
22	  if (!config.masterEncryptionKey || config.masterEncryptionKey.length < 64) {
23	    throw new Error('MASTER_ENCRYPTION_KEY must be at least 64 hex characters');
24	  }
25	}
