1	import mongoose, { Schema, Document } from 'mongoose';
2	import { JobType, JobStatus, RateType } from '../types/enums';
3	
4	export interface IJob extends Document {
5	  title: string;
6	  description: string;
7	  clientId: mongoose.Types.ObjectId;
8	  photographerId?: mongoose.Types.ObjectId;
9	  communityId: string;
10	  jobType: JobType;
11	  status: JobStatus;
12	  rateType: RateType;
13	  agreedRateCents: number;
14	  estimatedTotalCents: number;
15	  serviceAgreementId?: mongoose.Types.ObjectId;
16	  clientConfirmed: boolean;
17	  photographerConfirmed: boolean;
18	  completedAt?: Date;
19	}
20	
21	const JobSchema = new Schema<IJob>({
22	  title: { type: String, required: true },
23	  description: { type: String, required: true },
24	  clientId: { type: Schema.Types.ObjectId, ref: 'User', required: true },
25	  photographerId: { type: Schema.Types.ObjectId, ref: 'User' },
26	  communityId: { type: String, required: true },
27	  jobType: { type: String, enum: Object.values(JobType), required: true },
28	  status: { type: String, enum: Object.values(JobStatus), default: JobStatus.DRAFT },
29	  rateType: { type: String, enum: Object.values(RateType), required: true },
30	  agreedRateCents: { type: Number, required: true },
31	  estimatedTotalCents: { type: Number, default: 0 },
32	  serviceAgreementId: { type: Schema.Types.ObjectId, ref: 'ServiceAgreement' },
33	  clientConfirmed: { type: Boolean, default: false },
34	  photographerConfirmed: { type: Boolean, default: false },
35	  completedAt: Date,
36	}, { timestamps: true });
37	
38	JobSchema.index({ clientId: 1, status: 1 });
39	JobSchema.index({ photographerId: 1, status: 1 });
40	JobSchema.index({ communityId: 1, status: 1 });
41	
42	export const Job = mongoose.model<IJob>('Job', JobSchema);
