33	router.get('/users', authorize(Role.ADMIN), async (req: Request, res: Response, next: NextFunction) => {
34	  try {
35	    const page = parseInt(req.query.page as string) || 1;
36	    const limit = parseInt(req.query.limit as string) || 20;
