46	    await AuditLog.create({ timestamp: new Date(), actorId: req.user!.userId, action: AUDIT_EVENTS.ROLE_CHANGE, resource: 'user', resourceId: req.params.id, details: { newRole: req.body.role }, outcome: 'success' });
47	    res.json(user);
