54	    await AuditLog.create({ timestamp: new Date(), actorId: req.user!.userId, action: AUDIT_EVENTS.PERMISSION_CHANGE, resource: 'user', resourceId: req.params.id, details: { newStatus: req.body.accountStatus }, outcome: 'success' });
