2	import helmet from 'helmet';
3	import cors from 'cors';
4	import { requestId } from './middleware/requestId';
5	import { rateLimiter, accountRateLimiter } from './middleware/rateLimiter';
6	import { nonceReplay } from './middleware/nonceReplay';
7	import { auditLogger } from './middleware/auditLogger';
8	import { authenticate } from './middleware/authenticate';
9	import { blacklistCheck } from './middleware/blacklistCheck';
10	import { deviceFingerprintMiddleware } from './middleware/deviceFingerprint';
11	import { errorHandler } from './middleware/errorHandler';
12	import { mountRoutes } from './routes';
13	
14	const app = express();
15	
16	// 1. Security headers
17	app.use(helmet({
18	  contentSecurityPolicy: {
19	    directives: {
20	      defaultSrc: ["'self'"],
21	      scriptSrc: ["'self'"],
22	      styleSrc: ["'self'", "'unsafe-inline'"],
23	      imgSrc: ["'self'", "data:"],
24	    },
25	  },
26	  hsts: { maxAge: 31536000, includeSubDomains: true },
27	}));
28	
29	// 2. CORS
30	app.use(cors({
31	  origin: true,
32	  credentials: true,
33	  methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE'],
34	  allowedHeaders: ['Content-Type', 'Authorization', 'X-Nonce', 'X-Timestamp', 'X-Device-Fingerprint', 'X-Request-Id'],
35	}));
36	
37	// 3. Body parsing
38	app.use(express.json({ limit: '10mb' }));
39	app.use(express.urlencoded({ extended: true, limit: '10mb' }));
40	
41	// 4. Request ID
42	app.use(requestId);
43	
44	// 5. Rate limiting (before auth to catch brute force)
45	app.use(rateLimiter);
46	
47	// 6. Nonce replay protection
48	app.use(nonceReplay);
49	
50	// 7. Audit logger (pre)
51	app.use(auditLogger);
52	
53	// 8. Authentication
54	app.use(authenticate);
55	
56	// 9. Per-account rate limiter (post-auth)
57	app.use(accountRateLimiter);
58	
59	// 10. Blacklist check
60	app.use(blacklistCheck);
61	
62	// 11. Device fingerprint (consent-gated)
63	app.use(deviceFingerprintMiddleware);
64	
65	// 12. Routes
66	mountRoutes(app);
67	
68	// 13. Error handler (must be last)
69	app.use(errorHandler);
70	
71	export default app;
72

1	import { Request, Response, NextFunction } from 'express';
2	import { AppError } from '../utils/errors';
3	import { logger } from '../utils/logger';
4	
5	export function errorHandler(err: Error, req: Request, res: Response, _next: NextFunction): void {
6	  if (err instanceof AppError) {
7	    res.status(err.statusCode).json({
8	      code: err.statusCode,
9	      msg: err.message,
10	    });
11	    return;
12	  }
13	
14	  logger.error('Unhandled error', {
15	    error: err.message,
16	    stack: err.stack,
17	    path: req.path,
18	    method: req.method,
19	    requestId: req.requestId,
20	  });
21	
22	  res.status(500).json({
23	    code: 500,
24	    msg: 'Internal server error',
25	  });
26	}
