4	import { validateRequest } from '../middleware/validateRequest';
5	import { authorize } from '../middleware/authorize';
6	import { Role } from '../types/enums';
7	
8	const router = Router();
9	// Settlement operations (mounted at /api/settlements)
10	router.get('/:id', authorize(Role.ALUMNI, Role.PHOTOGRAPHER, Role.ADMIN), validateRequest(settlementCtrl.settlementIdParamSchema, 'params'), settlementCtrl.getById);
11	router.patch('/:id/approve', authorize(Role.ALUMNI, Role.PHOTOGRAPHER, Role.ADMIN), validateRequest(settlementCtrl.settlementIdParamSchema, 'params'), settlementCtrl.approve);
12	router.post('/:id/adjustment', authorize(Role.ALUMNI, Role.PHOTOGRAPHER, Role.ADMIN), validateRequest(settlementCtrl.settlementIdParamSchema, 'params'), settlementCtrl.addAdjustment);
13	router.get('/:id/export/pdf', authorize(Role.ALUMNI, Role.PHOTOGRAPHER, Role.ADMIN), validateRequest(settlementCtrl.settlementIdParamSchema, 'params'), settlementCtrl.exportPDF);
14	router.get('/:id/export/csv', authorize(Role.ALUMNI, Role.PHOTOGRAPHER, Role.ADMIN), validateRequest(settlementCtrl.settlementIdParamSchema, 'params'), settlementCtrl.exportCSV);
15	// Payment operations
16	router.post('/:id/payments', authorize(Role.ALUMNI, Role.PHOTOGRAPHER, Role.ADMIN), validateRequest(paymentCtrl.settlementIdParamSchema, 'params'), validateRequest(paymentCtrl.recordPaymentSchema), paymentCtrl.recordPayment);
17	router.get('/:id/payments', authorize(Role.ALUMNI, Role.PHOTOGRAPHER, Role.ADMIN), validateRequest(paymentCtrl.settlementIdParamSchema, 'params'), paymentCtrl.getBySettlement);
18	export default router;
