12	  [JobStatus.COMPLETED]: [],
13	  [JobStatus.CANCELLED]: [],
14	  [JobStatus.DISPUTED]: [JobStatus.IN_PROGRESS, JobStatus.CANCELLED, JobStatus.COMPLETED],
