242	export async function listJobs(filters: {
243	  clientId?: string;
244	  photographerId?: string;
245	  communityId?: string;
246	  status?: JobStatus;
247	  page?: number;
248	  limit?: number;
249	}) {
250	  const page = filters.page || 1;
251	  const limit = filters.limit || 20;
252	  const skip = (page - 1) * limit;
253	
254	  const query: any = {};
255	  if (filters.clientId) query.clientId = filters.clientId;
256	  if (filters.photographerId) query.photographerId = filters.photographerId;
257	  if (filters.communityId) query.communityId = filters.communityId;
258	  if (filters.status) query.status = filters.status;
259	
260	  const [jobs, total] = await Promise.all([
261	    Job.find(query).sort({ createdAt: -1 }).skip(skip).limit(limit).lean(),
262	    Job.countDocuments(query),
263	  ]);
264	
265	  return { jobs, total, page, limit };
266	}
