1	import { WorkEntry, Job } from '../models';
2	import { WorkEntryType, JobStatus } from '../types/enums';
3	import { NotFoundError, ValidationError, ForbiddenError } from '../utils/errors';
4	import { calculateTimeEntryCents, calculatePieceRateCents } from '../utils/money';
5	import { TIMESHEET_INCREMENT_MINUTES, LOCK_HOURS } from '../utils/constants';
6	
7	export interface CreateWorkEntryInput {
8	  jobId: string;
9	  photographerId: string;
10	  entryType: WorkEntryType;
11	  date?: Date;
12	  startTime?: string;
13	  endTime?: string;
14	  durationMinutes?: number;
15	  itemDescription?: string;
16	  quantity?: number;
17	  unitRateCents?: number;
18	  notes?: string;
19	}
20	
21	/**
22	 * Create a work entry. For TIME entries, validate 15-minute alignment.
23	 */
24	export async function createWorkEntry(input: CreateWorkEntryInput) {
25	  const job = await Job.findById(input.jobId);
26	  if (!job) {
27	    throw new NotFoundError('Job not found');
28	  }
29	
30	  if (
31	    job.status !== JobStatus.IN_PROGRESS &&
32	    job.status !== JobStatus.REVIEW
33	  ) {
34	    throw new ValidationError('Work entries can only be added to in-progress or review jobs');
35	  }
36	
37	  if (job.photographerId?.toString() !== input.photographerId) {
38	    throw new ForbiddenError('Only the assigned photographer can create work entries');
39	  }
40	
41	  let subtotalCents: number;
42	
43	  if (input.entryType === WorkEntryType.TIME) {
44	    if (!input.durationMinutes || input.durationMinutes <= 0) {
45	      throw new ValidationError('Duration in minutes is required for time entries');
46	    }
47	
48	    // Validate 15-minute alignment
49	    if (input.durationMinutes % TIMESHEET_INCREMENT_MINUTES !== 0) {
50	      throw new ValidationError(
51	        `Duration must be in ${TIMESHEET_INCREMENT_MINUTES}-minute increments`
52	      );
53	    }
54	
55	    subtotalCents = calculateTimeEntryCents(job.agreedRateCents, input.durationMinutes);
56	  } else {
57	    // PIECE_RATE
58	    if (!input.quantity || input.quantity <= 0) {
59	      throw new ValidationError('Quantity is required for piece rate entries');
60	    }
61	
62	    const unitRate = input.unitRateCents ?? job.agreedRateCents;
63	    subtotalCents = calculatePieceRateCents(unitRate, input.quantity);
64	  }
65	
66	  const entry = await WorkEntry.create({
67	    jobId: input.jobId,
68	    photographerId: input.photographerId,
69	    entryType: input.entryType,
70	    date: input.date || new Date(),
71	    startTime: input.startTime,
72	    endTime: input.endTime,
73	    durationMinutes: input.durationMinutes,
74	    itemDescription: input.itemDescription,
75	    quantity: input.quantity,
76	    unitRateCents: input.unitRateCents,
77	    subtotalCents,
78	    notes: input.notes,
79	    isLocked: false,
80	  });
81	
82	  return entry;
83	}
84	
85	/**
86	 * Edit a work entry. Resets both confirmations.
87	 */
88	export async function editWorkEntry(
89	  entryId: string,
90	  userId: string,
91	  updates: Partial<CreateWorkEntryInput>
92	) {
93	  const entry = await WorkEntry.findById(entryId);
94	  if (!entry) {
95	    throw new NotFoundError('Work entry not found');
96	  }
97	
98	  if (entry.isLocked) {
99	    throw new ValidationError('Cannot edit a locked work entry');
100	  }
101	
102	  if (entry.photographerId.toString() !== userId) {
103	    throw new ForbiddenError('Only the photographer can edit their work entries');
104	  }
105	
106	  // If duration is being updated, validate alignment
107	  if (updates.durationMinutes !== undefined) {
108	    if (updates.durationMinutes % TIMESHEET_INCREMENT_MINUTES !== 0) {
109	      throw new ValidationError(
110	        `Duration must be in ${TIMESHEET_INCREMENT_MINUTES}-minute increments`
111	      );
112	    }
113	  }
114	
115	  // Recalculate subtotal if relevant fields changed
116	  const job = await Job.findById(entry.jobId);
117	  if (!job) {
118	    throw new NotFoundError('Associated job not found');
119	  }
120	
121	  const entryType = updates.entryType || entry.entryType;
122	  let subtotalCents = entry.subtotalCents;
123	
124	  if (entryType === WorkEntryType.TIME) {
125	    const duration = updates.durationMinutes ?? entry.durationMinutes;
126	    if (duration) {
127	      subtotalCents = calculateTimeEntryCents(job.agreedRateCents, duration);
128	    }
129	  } else {
130	    const quantity = updates.quantity ?? entry.quantity;
131	    const unitRate = updates.unitRateCents ?? entry.unitRateCents ?? job.agreedRateCents;
132	    if (quantity) {
133	      subtotalCents = calculatePieceRateCents(unitRate, quantity);
134	    }
135	  }
136	
137	  // Apply updates and reset confirmations
138	  Object.assign(entry, updates, {
139	    subtotalCents,
140	    clientConfirmedAt: undefined,
141	    photographerConfirmedAt: undefined,
142	    lockAt: undefined,
143	  });
144	
145	  // Use $unset for clearing confirmation dates
146	  await WorkEntry.findByIdAndUpdate(entryId, {
147	    $set: {
148	      ...updates,
149	      subtotalCents,
150	    },
151	    $unset: {
152	      clientConfirmedAt: 1,
153	      photographerConfirmedAt: 1,
154	      lockAt: 1,
155	    },
156	  });
157	
158	  return WorkEntry.findById(entryId);
159	}
