1	import { ContentReview } from '../models';
2	import { ContentReviewStatus, ReviewableContentType } from '../types/enums';
3	import { NotFoundError, ValidationError } from '../utils/errors';
4	
5	export async function submitForReview(contentType: ReviewableContentType, contentId: string, submittedBy: string, flaggedWords: string[]) {
6	  return ContentReview.create({ contentType, contentId, submittedBy, flaggedWords, status: ContentReviewStatus.PENDING });
7	}
8	
9	export async function getPending(page = 1, limit = 20) {
10	  const skip = (page - 1) * limit;
11	  const [items, total] = await Promise.all([
12	    ContentReview.find({ status: ContentReviewStatus.PENDING }).sort({ createdAt: -1 }).skip(skip).limit(limit),
13	    ContentReview.countDocuments({ status: ContentReviewStatus.PENDING }),
14	  ]);
15	  return { items, total, page, limit };
16	}
17	
18	export async function reviewContent(id: string, reviewedBy: string, status: ContentReviewStatus, reviewNotes?: string) {
19	  const review = await ContentReview.findById(id);
20	  if (!review) throw new NotFoundError('Content review not found');
21	
22	  if (review.status !== ContentReviewStatus.PENDING) {
23	    throw new ValidationError(
24	      `Cannot review content with status "${review.status}". Only pending content can be reviewed.`
25	    );
26	  }
27	
28	  review.status = status;
29	  review.reviewedBy = reviewedBy as any;
30	  review.reviewNotes = reviewNotes;
31	  review.reviewedAt = new Date();
32	  await review.save();
33	
34	  // Propagate decision to the source content
35	  await propagateDecision(review.contentType as ReviewableContentType, review.contentId.toString(), status);
36	
37	  return review;
38	}
39	
40	async function propagateDecision(contentType: ReviewableContentType, contentId: string, status: ContentReviewStatus) {
41	  if (contentType === ReviewableContentType.JOB_MESSAGE) {
42	    const { JobMessage } = await import('../models');
43	    await JobMessage.findByIdAndUpdate(contentId, { reviewStatus: status });
44	  } else if (contentType === ReviewableContentType.PORTFOLIO) {
45	    const { Portfolio } = await import('../models');
46	    await Portfolio.findByIdAndUpdate(contentId, { reviewStatus: status });
47	  }
48	}
