1	import crypto from 'crypto';
2	import { Request, Response, NextFunction } from 'express';
3	import { Nonce } from '../models/Nonce';
4	import { config } from '../config';
5	import { ConflictError, ValidationError, UnprocessableError } from '../utils/errors';
6	
7	const NONCE_EXEMPT_PATHS = [
8	  'GET:/api/health',
9	];
10	
11	export async function nonceReplay(req: Request, _res: Response, next: NextFunction): Promise<void> {
12	  try {
13	    const routeKey = `${req.method}:${req.path}`;
14	    if (NONCE_EXEMPT_PATHS.includes(routeKey)) {
15	      return next();
16	    }
17	
18	    const nonce = req.headers['x-nonce'] as string;
19	    const timestamp = req.headers['x-timestamp'] as string;
20	
21	    if (!nonce || !timestamp) {
22	      const isMutation = ['POST', 'PUT', 'PATCH', 'DELETE'].includes(req.method);
23	      const ErrorClass = isMutation ? UnprocessableError : ValidationError;
24	      return next(new ErrorClass('X-Nonce and X-Timestamp headers are required'));
25	    }
26	
27	    const requestTime = parseInt(timestamp, 10);
28	    if (isNaN(requestTime)) {
29	      return next(new ValidationError('Invalid X-Timestamp header'));
30	    }
31	
32	    const now = Date.now();
33	    const diff = Math.abs(now - requestTime);
34	
35	    if (diff > config.nonceWindowMs + config.clockSkewMs) {
36	      return next(new ValidationError('Request timestamp outside acceptable window'));
37	    }
38	
39	    // Bind the nonce to the request method and path so a captured nonce
40	    // cannot be replayed against a different endpoint.
41	    const boundNonce = crypto
42	      .createHash('sha256')
43	      .update(`${nonce}:${req.method}:${req.path}`)
44	      .digest('hex');
45	
46	    const existing = await Nonce.findOne({ nonce: boundNonce });
47	    if (existing) {
48	      return next(new ConflictError('Duplicate nonce detected - possible replay attack'));
49	    }
50	
51	    await Nonce.create({ nonce: boundNonce, timestamp: new Date(requestTime) });
52	    req.nonce = nonce;
53	    next();
54	  } catch (err) {
55	    next(err);
56	  }
57	}
