+        createdAt: new Date(),
+        updatedAt: new Date(),
+      });
+      rejectedId = result.insertedId.toString();
+    } finally { await conn.close(); }
+
+    // First reject it
+    const rejectRes = await request('PATCH', `/api/admin/content-reviews/${rejectedId}`, {
+      status: 'rejected', reviewNotes: 'Not appropriate',
+    }, adminToken);
