4	export async function upload(jobId: string, uploaderId: string, filePath: string, copyrightNotice: string, uploadedBy: string) {
5	  const job = await Job.findById(jobId);
6	  if (!job) throw new NotFoundError('Job not found');
7	
8	  // Only the assigned photographer (or admin) can upload deliverables
9	  const uploader = await User.findById(uploaderId);
10	  if (uploader?.role !== 'admin') {
11	    if (!job.photographerId || job.photographerId.toString() !== uploaderId) {
12	      throw new ForbiddenError('Only the assigned photographer can upload deliverables');
13	    }
14	  }
15	
16	  if (!copyrightNotice) throw new ValidationError('Copyright notice is required');
17	  return Deliverable.create({ jobId, photographerId: uploaderId, filePath, copyrightNotice, uploadedBy, visibleTo: [uploadedBy] });
18	}
19	
20	export async function getByJob(jobId: string, requesterId: string) {
21	  const job = await Job.findById(jobId);
22	  if (!job) throw new NotFoundError('Job not found');
23	
24	  const requester = await User.findById(requesterId);
25	  if (requester?.role !== 'admin') {
26	    const isParticipant =
27	      job.clientId.toString() === requesterId ||
28	      (job.photographerId && job.photographerId.toString() === requesterId);
29	    if (!isParticipant) {
30	      throw new ForbiddenError('Only job participants can view deliverables');
31	    }
32	  }
33	
34	  return Deliverable.find({ jobId }).sort({ createdAt: -1 });
35	}
