114	      </div>
115	
116	      <div className="bg-white rounded-lg shadow">
117	        {items.length === 0 ? (
118	          <p className="p-6 text-sm text-gray-500">No {tab} requests.</p>
119	        ) : (
120	          <table className="w-full text-sm">
121	            <thead>
122	              <tr className="border-b bg-gray-50">
123	                <th className="text-left px-6 py-3">{tab === 'incoming' ? 'From' : 'To'}</th>
124	                <th className="text-left px-6 py-3">Fields</th>
125	                <th className="text-left px-6 py-3">Reason</th>
126	                <th className="text-left px-6 py-3">Status</th>
127	                <th className="text-left px-6 py-3">Date</th>
128	                {tab === 'incoming' && <th className="text-left px-6 py-3">Actions</th>}
129	              </tr>
130	            </thead>
131	            <tbody>
132	              {items.map((req: any) => (
133	                <tr key={req._id} className="border-b">
134	                  <td className="px-6 py-3 font-mono text-xs">{tab === 'incoming' ? req.requesterId : req.targetUserId}</td>
135	                  <td className="px-6 py-3">{(req.fields || []).join(', ')}</td>
136	                  <td className="px-6 py-3 text-gray-600 max-w-xs truncate">{req.reason}</td>
137	                  <td className="px-6 py-3"><StatusBadge status={req.status} /></td>
138	                  <td className="px-6 py-3">{formatDateTime(req.createdAt || req.expiresAt)}</td>
139	                  {tab === 'incoming' && (
140	                    <td className="px-6 py-3">
141	                      {req.status === 'pending' && (
142	                        <div className="flex gap-2">
143	                          <button onClick={() => handleAction(req._id, 'approve')} disabled={actionLoading === req._id} className="text-green-600 hover:underline text-xs disabled:opacity-50">Approve</button>
144	                          <button onClick={() => handleAction(req._id, 'deny')} disabled={actionLoading === req._id} className="text-red-600 hover:underline text-xs disabled:opacity-50">Deny</button>
145	                        </div>
146	                      )}
147	                    </td>
148	                  )}
149	                </tr>
150	              ))}
151	            </tbody>
152	          </table>
153	        )}
154	      </div>
155	    </div>
156	  );
157	}
