1	import crypto from 'crypto';
2	import { Request, Response, NextFunction } from 'express';
3	import { Nonce } from '../models/Nonce';
4	import { config } from '../config';
5	import { ConflictError, ValidationError } from '../utils/errors';
6	
7	const NONCE_EXEMPT_PATHS = [
8	  'GET:/api/health',
9	];
10	
11	export async function nonceReplay(req: Request, _res: Response, next: NextFunction): Promise<void> {
12	  try {
13	    const routeKey = `${req.method}:${req.path}`;
14	    if (NONCE_EXEMPT_PATHS.includes(routeKey)) {
15	      return next();
16	    }
17	
18	    const nonce = req.headers['x-nonce'] as string;
19	    const timestamp = req.headers['x-timestamp'] as string;
20	
21	    if (!nonce || !timestamp) {
22	      const isMutation = ['POST', 'PUT', 'PATCH', 'DELETE'].includes(req.method);
23	      const code = isMutation ? 422 : 400;
24	      _res.status(code).json({ code, msg: 'X-Nonce and X-Timestamp headers are required' });
25	      return;
26	    }
27	
28	    const requestTime = parseInt(timestamp, 10);
29	    if (isNaN(requestTime)) {
30	      return next(new ValidationError('Invalid X-Timestamp header'));
31	    }
32	
33	    const now = Date.now();
34	    const diff = Math.abs(now - requestTime);
35	
36	    if (diff > config.nonceWindowMs + config.clockSkewMs) {
37	      return next(new ValidationError('Request timestamp outside acceptable window'));
38	    }
39	
40	    // Bind the nonce to the request method and path so a captured nonce
41	    // cannot be replayed against a different endpoint.
42	    const boundNonce = crypto
43	      .createHash('sha256')
44	      .update(`${nonce}:${req.method}:${req.path}`)
45	      .digest('hex');
46	
47	    const existing = await Nonce.findOne({ nonce: boundNonce });
48	    if (existing) {
49	      return next(new ConflictError('Duplicate nonce detected - possible replay attack'));
50	    }
51	
52	    await Nonce.create({ nonce: boundNonce, timestamp: new Date(requestTime) });
53	    req.nonce = nonce;
54	    next();
55	  } catch (err) {
56	    next(err);
57	  }
58	}
